import{_ as o,o as e,c as a,a5 as d}from"./chunks/framework.CW28V7p_.js";const p=JSON.parse('{"title":"Module 1 — Solana foundations","description":"","frontmatter":{},"headers":[],"relativePath":"module-1/index.md","filePath":"module-1/index.md","lastUpdated":1780937944000}'),l={name:"module-1/index.md"};function r(n,t,s,i,u,c){return e(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="module-1-—-solana-foundations" tabindex="-1">Module 1 — Solana foundations <a class="header-anchor" href="#module-1-—-solana-foundations" aria-label="Permalink to &quot;Module 1 — Solana foundations&quot;">​</a></h1><blockquote><p><strong>TL;DR.</strong> Перший Solana-специфічний модуль. Цілий курс будується на термінах з нього: <strong>cluster</strong>, <strong>slot</strong>, <strong>epoch</strong>, <strong>leader</strong>, <strong>block</strong>, <strong>validator status</strong>. Без цього модуль 4 (Consensus) не зрозуміти, без модуля 4 не зрозуміти що ти моніториш у щоденній роботі. Перший модуль = mental map &quot;що це за система і як вона рухається у часі&quot;.</p></blockquote><blockquote><p><strong>Як читати:</strong> послідовно. Кожна секція будується на попередній. Не пропускай — це foundation для всього курсу.</p></blockquote><h2 id="секціі" tabindex="-1">Секції <a class="header-anchor" href="#секціі" aria-label="Permalink to &quot;Секції&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Тема</th><th>Час</th><th>Status</th></tr></thead><tbody><tr><td>1</td><td><a href="/module-1/1-cluster">Cluster, network types, node kinds</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>2</td><td><a href="/module-1/2-slots-epochs">Slots, epochs, time на Solana</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>3</td><td><a href="/module-1/3-leaders">Leader, leader schedule, rotation</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>4</td><td><a href="/module-1/4-block-production">Block production (produce vs skip)</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>5</td><td><a href="/module-1/5-validator-status">Validator status (voting, delinquent, healthy)</a></td><td>30-40 хв</td><td>✅</td></tr><tr><td>⭐</td><td><a href="/module-1/final-quiz">Final quiz</a></td><td>30 хв</td><td>✅</td></tr></tbody></table><p><strong>Загальний час Module 1: 3-4 години.</strong></p><h2 id="як-перевірити-що-готова-до-module-2" tabindex="-1">Як перевірити що готова до Module 2 <a class="header-anchor" href="#як-перевірити-що-готова-до-module-2" aria-label="Permalink to &quot;Як перевірити що готова до Module 2&quot;">​</a></h2><p>Після Module 1 ти маєш знати без підглядання:</p><ul><li>Що таке cluster і чим відрізняються mainnet/testnet/devnet/Alpenglow</li><li>Що таке slot, epoch, скільки слотів в епоці, скільки часу триває epoch</li><li>Як вибирається leader для конкретного slot</li><li>Що значить &quot;validator skipped a slot&quot; і чи це погано</li><li>Як читати output <code>solana validators</code> (active vs delinquent stake)</li><li>Що показує <code>solana epoch-info</code> і чому це корисно</li></ul><p>Final quiz перевіряє все це. <strong>80%+ correct</strong> → Module 2 готовий.</p><h2 id="чому-ця-послідовність" tabindex="-1">Чому ця послідовність <a class="header-anchor" href="#чому-ця-послідовність" aria-label="Permalink to &quot;Чому ця послідовність&quot;">​</a></h2><ol><li><strong>Cluster першим</strong> — найвищий рівень, він тримає все інше. Поки не зрозуміла &quot;що таке Solana як мережа&quot; — далі не йдемо</li><li><strong>Slots/epochs другим</strong> — як Solana <strong>рухається у часі</strong>. Без цього всі інші концепти (leader rotation, voting, stake epochs) — magic</li><li><strong>Leader третім</strong> — slots дають &quot;коли&quot;, leader дає &quot;хто&quot;. Це core consensus primitive</li><li><strong>Block production четвертим</strong> — що <strong>відбувається</strong> у кожен slot. Зв&#39;язує leader + cluster</li><li><strong>Validator status п&#39;ятим</strong> — як <strong>тебе</strong> як operator стосується все вище. Voting/delinquent — те що моніториш щодня</li></ol>',12)])])}const g=o(l,[["render",r]]);export{p as __pageData,g as default};
